import { DEMO_AGENCY_ID, DEMO_TENANT_ID } from '@/lib/config';

/** Identifiant agence de la session (localStorage) ou fallback dev. */
export function getAgencyId(): string {
  if (typeof window === 'undefined') return DEMO_AGENCY_ID;
  return localStorage.getItem('tnt-agency-id') ?? DEMO_AGENCY_ID;
}

export function getTenantId(): string {
  if (typeof window === 'undefined') return DEMO_TENANT_ID;
  return localStorage.getItem('tnt-tenant-id') ?? DEMO_TENANT_ID;
}

export function getAuthToken(): string | null {
  if (typeof window === 'undefined') return null;
  return localStorage.getItem('tnt-token');
}
